import{c as l,Z as a,Q as d,j as u,g as t,n as o,o as s,m as n,av as h}from"./chunks/framework.BPKcPtvA.js";const k=JSON.parse('{"title":"Buy & sell with HavenBot","description":"Ask HavenBot to buy and sell in plain language — it previews each trade for you to authorize, with the device passkey needed only once per session.","frontmatter":{"title":"Buy & sell with HavenBot","description":"Ask HavenBot to buy and sell in plain language — it previews each trade for you to authorize, with the device passkey needed only once per session."},"headers":[],"relativePath":"guide/agent/autonomous.md","filePath":"guide/agent/autonomous.md","lastUpdated":1780231053000}'),c={name:"guide/agent/autonomous.md"};function p(g,e,m,y,f,b){const i=a("TaskMeta"),r=a("ExpectedResult");return d(),u("div",null,[e[1]||(e[1]=t("h1",{id:"buy-sell-with-havenbot",tabindex:"-1"},[o("Buy & sell with HavenBot "),t("a",{class:"header-anchor",href:"#buy-sell-with-havenbot","aria-label":'Permalink to "Buy & sell with HavenBot"'},"​")],-1)),s(i,{time:"~4 min",role:"Any signed-in user",needs:"A Scoped session armed (H3), some mhUSDC"}),e[2]||(e[2]=n('<blockquote><p><strong>What you&#39;ll do:</strong> tell HavenBot to <strong>buy</strong> and then <strong>sell</strong> in plain language. HavenBot previews each trade in a confirmation card you authorize — and after a one-time device passkey, authorizing is a single tap.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">How HavenBot signs with a live Scoped session</p><p>With a <strong>live Scoped session</strong> (<a href="/guide/agent/set-tier">H3</a>), HavenBot <strong>auto-executes</strong> your buys and sells: the confirmation card appears <strong>briefly and submits itself</strong> — <strong>no click, no passkey</strong> (the device passkey is needed only once per browser session, the first time). The card still flashes so you can see what ran, and every trade is recorded in the audit log. <strong>Without</strong> a live Scoped session (or after it expires), HavenBot falls back to a <strong>manual one-tap</strong> confirmation. Either way the trade stays within your per-trade cap.</p></div><h2 id="buy" tabindex="-1">Buy <a class="header-anchor" href="#buy" aria-label="Permalink to &quot;Buy&quot;">​</a></h2><ol><li>Open <strong>Agent</strong> (<code>/agent</code>).</li><li>Type a plain-language buy, e.g. <strong>&quot;Buy $5 of CETES.&quot;</strong></li><li>With a live Scoped session, HavenBot <strong>submits it automatically</strong> — the card flashes and self-authorizes, no click. After ~30–60s (gas is sponsored) HavenBot returns a <strong>transaction hash</strong>. (No session? You&#39;ll tap <strong>Authorize</strong> once instead.)</li></ol><h2 id="sell" tabindex="-1">Sell <a class="header-anchor" href="#sell" aria-label="Permalink to &quot;Sell&quot;">​</a></h2><ol><li>In the same chat, type <strong>&quot;Sell 2 shares of CETES.&quot;</strong></li><li>With a live Scoped session it submits automatically (same flash-and-go). The sell settles <strong>instantly</strong> within the token&#39;s per-epoch instant cap; a larger sell is <strong>queued</strong> and settles in a later epoch (claim it later — see <a href="/guide/investor/redemption-queue">I9 · Redemption-queue claim</a>).</li></ol><div class="tip custom-block"><p class="custom-block-title">Even more hands-off</p><ul><li><strong>Auto-reinvest</strong> — HavenBot automatically claims matured yield and buys more of the same token, with <strong>no card at all</strong> (opt-in on the policy page; runs on your Scoped session).</li><li><strong>Rebalance to targets</strong> — ask HavenBot to <em>&quot;rebalance my portfolio to these targets&quot;</em>. It executes <strong>one atomic transaction</strong> (sells before buys) on your Scoped session.</li></ul><p>Prefer a fully headless setup (e.g. from your own LLM/terminal)? The <a href="/guide/mcp/buy">MCP broker</a> holds your Scoped key and signs each trade server-side — no dashboard tab open at all.</p></div><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><ol><li>Open <a href="/guide/investor/activity">Activity</a>, or ask HavenBot <em>&quot;show my recent activity&quot;</em>.</li><li>Your buy and sell appear as settled rows within ~30–60s.</li></ol><div class="tip custom-block"><p class="custom-block-title">Stop anytime — just ask</p><p>Tell HavenBot <em>&quot;pause my agent&quot;</em> — it blocks every write instantly. You can also revoke the session from the dashboard or via Telegram. To resume, pick a tier again on the dashboard and confirm with your passkey.</p></div><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',12)),s(r,null,{default:h(()=>[...e[0]||(e[0]=[o(" With a live Scoped session, each buy and sell ",-1),t("strong",null,"self-authorizes",-1),o(" (the card flashes, no click, no passkey after the one-time first sign), lands a ",-1),t("strong",null,"tx hash",-1),o(" on-chain in ~30–60s, and shows up in ",-1),t("a",{href:"/guide/investor/activity"},"Activity",-1),o(". ",-1)])]),_:1}),e[3]||(e[3]=n('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>HavenBot shows a card you must tap (not auto)</td><td>No live Scoped session — arm one in <a href="/guide/agent/set-tier">H3 · Arm Scoped autonomy</a> (or it expired — re-arm).</td></tr><tr><td>The first trade asked for the device passkey</td><td>Expected — the in-tab signing session authorizes once per browser session; later trades are silent. A fresh tab re-authorizes once.</td></tr><tr><td>A sell was queued, not instant</td><td>The amount exceeded the per-epoch instant cap — settle the queued portion later (<a href="/guide/investor/redemption-queue">I9</a>).</td></tr><tr><td>HavenBot asks your passkey for a deposit/withdraw</td><td>Expected — converting USDC ↔ mhUSDC always uses a dashboard deep-link, never silent submission.</td></tr></tbody></table><p>→ Next: <a href="/guide/mcp/arm-scoped">Arm Scoped autonomy on the dashboard (MCP)</a></p>',3))])}const w=l(c,[["render",p]]);export{k as __pageData,w as default};
